"""Exercism task Exercism_tree-building"""
from pathlib import Path

TASK = """Implement the solution defined in tree_building.py. Make the tests pass.

Instructions:
# Instructions

Refactor a tree building algorithm.

Some web-forums have a tree layout, so posts are presented as a tree.
However the posts are typically stored in a database as an unsorted set of records.
Thus when presenting the posts to the user the tree structure has to be reconstructed.

Your job will be to refactor a working but slow and ugly piece of code that implements the tree building logic for highly abstracted records.
The records only contain an ID number and a parent ID number.
The ID number is always between 0 (inclusive) and the length of the record list (exclusive).
All records have a parent ID lower than their own ID, except for the root record, which has a parent ID that's equal to its own ID.

An example tree:

```text
root (ID: 0, parent ID: 0)
|-- child1 (ID: 1, parent ID: 0)
|    |-- grandchild1 (ID: 2, parent ID: 1)
|    +-- grandchild2 (ID: 4, parent ID: 1)
+-- child2 (ID: 3, parent ID: 0)
|    +-- grandchild3 (ID: 6, parent ID: 3)
+-- child3 (ID: 5, parent ID: 0)
```

"""

FILES = {
    "tree_building.py": "class Record:\n    def __init__(self, record_id, parent_id):\n        self.record_id = record_id\n        self.parent_id = parent_id\n\n\nclass Node:\n    def __init__(self, node_id):\n        self.node_id = node_id\n        self.children = []\n\n\ndef BuildTree(records):\n    root = None\n    records.sort(key=lambda x: x.record_id)\n    ordered_id = [i.record_id for i in records]\n    if records:\n        if ordered_id[-1] != len(ordered_id) - 1:\n            raise ValueError('broken tree')\n        if ordered_id[0] != 0:\n            raise ValueError('invalid')\n    trees = []\n    parent = {}\n    for i in range(len(ordered_id)):\n        for j in records:\n            if ordered_id[i] == j.record_id:\n                if j.record_id == 0:\n                    if j.parent_id != 0:\n                        raise ValueError('error!')\n                if j.record_id < j.parent_id:\n                    raise ValueError('something went wrong!')\n                if j.record_id == j.parent_id:\n                    if j.record_id != 0:\n                        raise ValueError('error!')\n                trees.append(Node(ordered_id[i]))\n    for i in range(len(ordered_id)):\n        for j in trees:\n            if i == j.node_id:\n                parent = j\n        for j in records:\n            if j.parent_id == i:\n                for k in trees:\n                    if k.node_id == 0:\n                        continue\n                    if j.record_id == k.node_id:\n                        child = k\n                        parent.children.append(child)\n    if len(trees) > 0:\n        root = trees[0]\n    return root\n",
    "tree_building_test.py": 'import unittest\n\nfrom tree_building import Record, BuildTree\n\n\nclass TreeBuildingTest(unittest.TestCase):\n    """\n        Record(record_id, parent_id): records given to be processed\n        Node(node_id): Node in tree\n        BuildTree(records): records as argument and returns tree\n        BuildTree should raise ValueError if given records are invalid\n    """\n\n    def test_empty_list_input(self):\n        records = []\n        root = BuildTree(records)\n        self.assertIsNone(root)\n\n    def test_one_node(self):\n        records = [\n            Record(0, 0)\n        ]\n        root = BuildTree(records)\n\n        self.assert_node_is_leaf(root, node_id=0)\n\n    def test_three_nodes_in_order(self):\n        records = [\n            Record(0, 0),\n            Record(1, 0),\n            Record(2, 0)\n        ]\n        root = BuildTree(records)\n\n        self.assert_node_is_branch(root, node_id=0, children_count=2)\n        self.assert_node_is_leaf(root.children[0], node_id=1)\n        self.assert_node_is_leaf(root.children[1], node_id=2)\n\n    def test_three_nodes_in_reverse_order(self):\n        records = [\n            Record(2, 0),\n            Record(1, 0),\n            Record(0, 0)\n        ]\n        root = BuildTree(records)\n\n        self.assert_node_is_branch(root, node_id=0, children_count=2)\n        self.assert_node_is_leaf(root.children[0], node_id=1)\n        self.assert_node_is_leaf(root.children[1], node_id=2)\n\n    def test_more_than_two_children(self):\n        records = [\n            Record(0, 0),\n            Record(1, 0),\n            Record(2, 0),\n            Record(3, 0)\n        ]\n        root = BuildTree(records)\n\n        self.assert_node_is_branch(root, node_id=0, children_count=3)\n        self.assert_node_is_leaf(root.children[0], node_id=1)\n        self.assert_node_is_leaf(root.children[1], node_id=2)\n        self.assert_node_is_leaf(root.children[2], node_id=3)\n\n    def test_binary_tree(self):\n        records = [\n            Record(6, 2),\n            Record(0, 0),\n            Record(3, 1),\n            Record(2, 0),\n            Record(4, 1),\n            Record(5, 2),\n            Record(1, 0)\n        ]\n        root = BuildTree(records)\n\n        self.assert_node_is_branch(root, 0, 2)\n        self.assert_node_is_branch(root.children[0], 1, 2)\n        self.assert_node_is_branch(root.children[1], 2, 2)\n        self.assert_node_is_leaf(root.children[0].children[0], 3)\n        self.assert_node_is_leaf(root.children[0].children[1], 4)\n        self.assert_node_is_leaf(root.children[1].children[0], 5)\n        self.assert_node_is_leaf(root.children[1].children[1], 6)\n\n    def test_unbalanced_tree(self):\n        records = [\n            Record(0, 0),\n            Record(1, 0),\n            Record(2, 0),\n            Record(3, 1),\n            Record(4, 1),\n            Record(5, 1),\n            Record(6, 2),\n        ]\n        root = BuildTree(records)\n\n        self.assert_node_is_branch(root, 0, 2)\n        self.assert_node_is_branch(root.children[0], 1, 3)\n        self.assert_node_is_branch(root.children[1], 2, 1)\n        self.assert_node_is_leaf(root.children[0].children[0], 3)\n        self.assert_node_is_leaf(root.children[0].children[1], 4)\n        self.assert_node_is_leaf(root.children[0].children[2], 5)\n        self.assert_node_is_leaf(root.children[1].children[0], 6)\n\n    def test_root_node_has_parent(self):\n        records = [\n            Record(0, 1),\n            Record(1, 0)\n        ]\n        # Root parent_id should be equal to record_id(0)\n        with self.assertRaises(ValueError) as err:\n            BuildTree(records)\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Node parent_id should be smaller than it\'s record_id.")\n\n    def test_no_root_node(self):\n        records = [\n            Record(1, 0),\n            Record(2, 0)\n        ]\n        # Record with record_id 0 (root) is missing\n        with self.assertRaises(ValueError) as err:\n            BuildTree(records)\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Record id is invalid or out of order.")\n\n    def test_non_continuous(self):\n        records = [\n            Record(2, 0),\n            Record(4, 2),\n            Record(1, 0),\n            Record(0, 0)\n        ]\n        # Record with record_id 3 is missing\n        with self.assertRaises(ValueError) as err:\n            BuildTree(records)\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Record id is invalid or out of order.")\n\n    def test_cycle_directly(self):\n        records = [\n            Record(5, 2),\n            Record(3, 2),\n            Record(2, 2),\n            Record(4, 1),\n            Record(1, 0),\n            Record(0, 0),\n            Record(6, 3)\n        ]\n        # Cycle caused by Record 2 with parent_id pointing to itself\n        with self.assertRaises(ValueError) as err:\n            BuildTree(records)\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Only root should have equal record and parent id.")\n\n    def test_cycle_indirectly(self):\n        records = [\n            Record(5, 2),\n            Record(3, 2),\n            Record(2, 6),\n            Record(4, 1),\n            Record(1, 0),\n            Record(0, 0),\n            Record(6, 3)\n        ]\n        # Cycle caused by Record 2 with parent_id(6) greater than record_id(2)\n        with self.assertRaises(ValueError) as err:\n            BuildTree(records)\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Node parent_id should be smaller than it\'s record_id.")\n\n    def test_higher_id_parent_of_lower_id(self):\n        records = [\n            Record(0, 0),\n            Record(2, 0),\n            Record(1, 2)\n        ]\n        # Record 1 have parent_id(2) greater than record_id(1)\n        with self.assertRaises(ValueError) as err:\n            BuildTree(records)\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Node parent_id should be smaller than it\'s record_id.")\n\n    def assert_node_is_branch(self, node, node_id, children_count):\n        self.assertEqual(node.node_id, node_id)\n        self.assertNotEqual(len(node.children), 0)\n        self.assertEqual(len(node.children), children_count)\n\n    def assert_node_is_leaf(self, node, node_id):\n        self.assertEqual(node.node_id, node_id)\n        self.assertEqual(len(node.children), 0)\n'
}

def check(workspace: Path) -> bool:
    import subprocess
    test_code = 'import unittest\n\nfrom tree_building import Record, BuildTree\n\n\nclass TreeBuildingTest(unittest.TestCase):\n    """\n        Record(record_id, parent_id): records given to be processed\n        Node(node_id): Node in tree\n        BuildTree(records): records as argument and returns tree\n        BuildTree should raise ValueError if given records are invalid\n    """\n\n    def test_empty_list_input(self):\n        records = []\n        root = BuildTree(records)\n        self.assertIsNone(root)\n\n    def test_one_node(self):\n        records = [\n            Record(0, 0)\n        ]\n        root = BuildTree(records)\n\n        self.assert_node_is_leaf(root, node_id=0)\n\n    def test_three_nodes_in_order(self):\n        records = [\n            Record(0, 0),\n            Record(1, 0),\n            Record(2, 0)\n        ]\n        root = BuildTree(records)\n\n        self.assert_node_is_branch(root, node_id=0, children_count=2)\n        self.assert_node_is_leaf(root.children[0], node_id=1)\n        self.assert_node_is_leaf(root.children[1], node_id=2)\n\n    def test_three_nodes_in_reverse_order(self):\n        records = [\n            Record(2, 0),\n            Record(1, 0),\n            Record(0, 0)\n        ]\n        root = BuildTree(records)\n\n        self.assert_node_is_branch(root, node_id=0, children_count=2)\n        self.assert_node_is_leaf(root.children[0], node_id=1)\n        self.assert_node_is_leaf(root.children[1], node_id=2)\n\n    def test_more_than_two_children(self):\n        records = [\n            Record(0, 0),\n            Record(1, 0),\n            Record(2, 0),\n            Record(3, 0)\n        ]\n        root = BuildTree(records)\n\n        self.assert_node_is_branch(root, node_id=0, children_count=3)\n        self.assert_node_is_leaf(root.children[0], node_id=1)\n        self.assert_node_is_leaf(root.children[1], node_id=2)\n        self.assert_node_is_leaf(root.children[2], node_id=3)\n\n    def test_binary_tree(self):\n        records = [\n            Record(6, 2),\n            Record(0, 0),\n            Record(3, 1),\n            Record(2, 0),\n            Record(4, 1),\n            Record(5, 2),\n            Record(1, 0)\n        ]\n        root = BuildTree(records)\n\n        self.assert_node_is_branch(root, 0, 2)\n        self.assert_node_is_branch(root.children[0], 1, 2)\n        self.assert_node_is_branch(root.children[1], 2, 2)\n        self.assert_node_is_leaf(root.children[0].children[0], 3)\n        self.assert_node_is_leaf(root.children[0].children[1], 4)\n        self.assert_node_is_leaf(root.children[1].children[0], 5)\n        self.assert_node_is_leaf(root.children[1].children[1], 6)\n\n    def test_unbalanced_tree(self):\n        records = [\n            Record(0, 0),\n            Record(1, 0),\n            Record(2, 0),\n            Record(3, 1),\n            Record(4, 1),\n            Record(5, 1),\n            Record(6, 2),\n        ]\n        root = BuildTree(records)\n\n        self.assert_node_is_branch(root, 0, 2)\n        self.assert_node_is_branch(root.children[0], 1, 3)\n        self.assert_node_is_branch(root.children[1], 2, 1)\n        self.assert_node_is_leaf(root.children[0].children[0], 3)\n        self.assert_node_is_leaf(root.children[0].children[1], 4)\n        self.assert_node_is_leaf(root.children[0].children[2], 5)\n        self.assert_node_is_leaf(root.children[1].children[0], 6)\n\n    def test_root_node_has_parent(self):\n        records = [\n            Record(0, 1),\n            Record(1, 0)\n        ]\n        # Root parent_id should be equal to record_id(0)\n        with self.assertRaises(ValueError) as err:\n            BuildTree(records)\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Node parent_id should be smaller than it\'s record_id.")\n\n    def test_no_root_node(self):\n        records = [\n            Record(1, 0),\n            Record(2, 0)\n        ]\n        # Record with record_id 0 (root) is missing\n        with self.assertRaises(ValueError) as err:\n            BuildTree(records)\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Record id is invalid or out of order.")\n\n    def test_non_continuous(self):\n        records = [\n            Record(2, 0),\n            Record(4, 2),\n            Record(1, 0),\n            Record(0, 0)\n        ]\n        # Record with record_id 3 is missing\n        with self.assertRaises(ValueError) as err:\n            BuildTree(records)\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Record id is invalid or out of order.")\n\n    def test_cycle_directly(self):\n        records = [\n            Record(5, 2),\n            Record(3, 2),\n            Record(2, 2),\n            Record(4, 1),\n            Record(1, 0),\n            Record(0, 0),\n            Record(6, 3)\n        ]\n        # Cycle caused by Record 2 with parent_id pointing to itself\n        with self.assertRaises(ValueError) as err:\n            BuildTree(records)\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Only root should have equal record and parent id.")\n\n    def test_cycle_indirectly(self):\n        records = [\n            Record(5, 2),\n            Record(3, 2),\n            Record(2, 6),\n            Record(4, 1),\n            Record(1, 0),\n            Record(0, 0),\n            Record(6, 3)\n        ]\n        # Cycle caused by Record 2 with parent_id(6) greater than record_id(2)\n        with self.assertRaises(ValueError) as err:\n            BuildTree(records)\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Node parent_id should be smaller than it\'s record_id.")\n\n    def test_higher_id_parent_of_lower_id(self):\n        records = [\n            Record(0, 0),\n            Record(2, 0),\n            Record(1, 2)\n        ]\n        # Record 1 have parent_id(2) greater than record_id(1)\n        with self.assertRaises(ValueError) as err:\n            BuildTree(records)\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Node parent_id should be smaller than it\'s record_id.")\n\n    def assert_node_is_branch(self, node, node_id, children_count):\n        self.assertEqual(node.node_id, node_id)\n        self.assertNotEqual(len(node.children), 0)\n        self.assertEqual(len(node.children), children_count)\n\n    def assert_node_is_leaf(self, node, node_id):\n        self.assertEqual(node.node_id, node_id)\n        self.assertEqual(len(node.children), 0)\n'
    (workspace / "tree_building_test.py").write_text(test_code, encoding="utf-8")
    try:
        res = subprocess.run(["python", "-m", "pytest", "-q", str(workspace / "tree_building_test.py")], timeout=15)
        return res.returncode == 0
    except subprocess.TimeoutExpired:
        return False
